import React from 'react';
import { useNavigate } from 'react-router-dom';

const caseList = [
  { id: 1, title: "Too Good to Be True? It Was.", image: "/images/homepage/case1.jpg" },
  { id: 2, title: "Oops… That Wasn't What I Thought!", image: "/images/homepage/case2.jpg" },
  { id: 3, title: "Not Your Average Snapchat Friend!", image: "/images/homepage/case3.jpg" },
  { id: 4, title: "Wait… Was That Even a Real Investment?", image: "/images/homepage/case4.jpg" }
];

export default function HomePage() {
  const navigate = useNavigate();

  return (
    <div style={{ backgroundColor: '#fff', minHeight: '100vh' }}>
      <div style={styles.container}>
        <h2 style={styles.sectionTitle}>
          🧑‍🏫 Learn from Real Cyber Incidents
        </h2>
        {caseList.map(item => (
          <div
            key={item.id}
            style={styles.card}
            onClick={() => navigate(`/home/case/${item.id}`)}
          >
            <img src={item.image} alt={`case ${item.id}`} style={styles.image} />
            <p style={styles.title}>{item.title}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

const styles = {
  sectionTitle: {
  textAlign: 'center',
  fontSize: '1.2em',
  marginBottom: '1em',
  color: '#333',
  fontWeight: '500'
},
  container: {
    padding: '1em',
    fontFamily: 'Arial, sans-serif',
    maxWidth: '600px',
    margin: '0 auto',
  },
  logo: {
    textAlign: 'center',
    fontWeight: 'bold',
    fontSize: '1.8em',
    marginBottom: '1.5em',
  },
  card: {
    backgroundColor: '#f9f9f9',
    marginBottom: '1em',
    padding: '1em',
    borderRadius: '15px',
    display: 'flex',
    alignItems: 'center',
    gap: '1em',
    cursor: 'pointer',
    boxShadow: '0 2px 6px rgba(0,0,0,0.1)',
    transition: 'transform 0.2s',
  },
  image: {
    width: '80px',
    height: '80px',
    borderRadius: '12px',
    objectFit: 'cover',
  },
  title: {
    flex: 1,
    fontWeight: '500',
    fontSize: '1em',
  },
};
